import { Pressable, Text, View } from 'react-native';
import Svg, { Path } from 'react-native-svg';

import { useAppTheme } from '@/modules/theme/ThemeProvider';
import { type AppTheme } from '@/modules/theme/tokens/theme';

import { getBottomBarTokens } from './bottomBarTokens';

type BottomBarTab = 'Library' | 'Book' | 'Settings';

type BottomBarProps = {
  activeTab?: BottomBarTab;
  onLibraryPress?: () => void;
  onBookPress?: () => void;
  onSettingsPress?: () => void;
  themeOverride?: AppTheme;
};

export function BottomBar({
  activeTab = 'Book',
  onLibraryPress,
  onBookPress,
  onSettingsPress,
  themeOverride,
}: BottomBarProps) {
  const appTheme = useAppTheme();
  const theme = themeOverride ?? appTheme;
  const bottomBarTokens = getBottomBarTokens(theme);
  const isLibrary = activeTab === 'Library';
  const isBook = activeTab === 'Book';
  const isSettings = activeTab === 'Settings';
  const fabShadow = isBook
    ? bottomBarTokens.fabShadowSelected
    : bottomBarTokens.fabShadowNormal;

  return (
    <View
      style={{
        width: '100%',
        height: bottomBarTokens.containerHeight,
        justifyContent: 'flex-end',
        position: 'relative',
      }}
    >
      <View
        style={{
          height: bottomBarTokens.navHeight,
          position: 'relative',
        }}
      >
        <View
          style={{
            position: 'absolute',
            left: 0,
            right: 0,
            top: bottomBarTokens.curveTop,
            height: bottomBarTokens.curveHeight,
            ...bottomBarTokens.navShadow,
          }}
        >
          <CurveBackground navBackground={bottomBarTokens.navBackground} />
        </View>

        <View
          style={{
            position: 'absolute',
            left: 0,
            right: 0,
            top: 0,
            height: bottomBarTokens.navHeight,
            paddingHorizontal: 24,
            flexDirection: 'row',
            alignItems: 'flex-start',
          }}
        >
          <BottomBarButton
            label="Library"
            isActive={isLibrary}
            onPress={onLibraryPress}
            theme={theme}
            icon={
              <LibraryIcon
                isActive={isLibrary}
                inactiveColor={bottomBarTokens.inactiveIconColor}
                activeColor={bottomBarTokens.activeIconColor}
              />
            }
          />

          <View
            style={{
              flex: 1,
              height: 75,
              justifyContent: 'flex-end',
              alignItems: 'center',
              paddingHorizontal: 15,
              paddingVertical: 12.5,
            }}
          >
            <Text
              style={{
                ...theme.typography.caption,
                color: isBook
                  ? bottomBarTokens.activeLabelColor
                  : bottomBarTokens.inactiveLabelColor,
              }}
            >
              Book
            </Text>
          </View>

          <BottomBarButton
            label="Settings"
            isActive={isSettings}
            onPress={onSettingsPress}
            theme={theme}
            icon={
              <SettingsIcon
                isActive={isSettings}
                inactiveColor={bottomBarTokens.inactiveIconColor}
                activeColor={bottomBarTokens.activeIconColor}
              />
            }
          />
        </View>
      </View>

      <Pressable
        onPress={onBookPress}
        style={{
          position: 'absolute',
          left: '50%',
          marginLeft: -bottomBarTokens.fabSize / 2,
          bottom: bottomBarTokens.fabBottom,
          width: bottomBarTokens.fabSize,
          height: bottomBarTokens.fabSize,
          borderRadius: bottomBarTokens.fabSize / 2,
          backgroundColor: isBook
            ? bottomBarTokens.fabBackgroundSelected
            : bottomBarTokens.fabBackgroundNormal,
          opacity: bottomBarTokens.fabOpacity,
          alignItems: 'center',
          justifyContent: 'center',
          ...fabShadow,
        }}
      >
        <View
          style={{
            position: 'absolute',
            top: 0,
            right: 0,
            bottom: 0,
            left: 0,
            borderRadius: bottomBarTokens.fabSize / 2,
            borderWidth: 1,
            borderColor: bottomBarTokens.fabGlassBorderColor,
            opacity: bottomBarTokens.fabGlassBorderOpacity,
          }}
        />
        <View
          style={{
            position: 'absolute',
            top: 0,
            right: 0,
            bottom: 0,
            left: 0,
            borderRadius: bottomBarTokens.fabSize / 2,
            backgroundColor: theme.colors.white,
            opacity: bottomBarTokens.fabGlassSheenOpacity,
          }}
        />
        <BookIcon
          isActive={isBook}
          activeColor={bottomBarTokens.fabIconSelected}
          inactiveColor={bottomBarTokens.fabIconNormal}
        />
      </Pressable>
    </View>
  );
}

function BottomBarButton({
  label,
  isActive,
  onPress,
  icon,
  theme,
}: {
  label: string;
  isActive: boolean;
  onPress?: () => void;
  icon: React.ReactNode;
  theme: AppTheme;
}) {
  const bottomBarTokens = getBottomBarTokens(theme);

  return (
    <Pressable
      onPress={onPress}
      style={{
        flex: 1,
        height: 75,
        alignItems: 'center',
        justifyContent: 'center',
        paddingHorizontal: 15,
        paddingVertical: 12.5,
        gap: 12,
      }}
    >
      <View
        style={{
          width: bottomBarTokens.iconSize,
          height: bottomBarTokens.iconSize,
        }}
      >
        {icon}
      </View>
      <Text
        style={{
          ...theme.typography.caption,
          color: isActive
            ? bottomBarTokens.activeLabelColor
            : bottomBarTokens.inactiveLabelColor,
        }}
      >
        {label}
      </Text>
    </Pressable>
  );
}

function CurveBackground({ navBackground }: { navBackground: string }) {
  return (
    <Svg width="100%" height="100%" viewBox="0 0 428 119" preserveAspectRatio="none">
      <Path
        d="M214 0C228.146 0 240.385 8.15921 246.27 20.0282C249.44 26.4221 255.179 32 262.316 32H422C425.314 32 428 34.6863 428 38V93C428 107.359 416.359 119 402 119H26C11.6406 119 0 107.359 0 93V38C0 34.6863 2.68629 32 6 32H165.684C172.821 32 178.56 26.4221 181.73 20.0282C187.615 8.15921 199.854 0 214 0ZM214 1C201.534 1 190.592 7.51702 184.392 17.3298C179.927 24.3965 186.553 32 194.912 32H233.088C241.447 32 248.073 24.3965 243.608 17.3298C237.408 7.51702 226.466 1 214 1Z"
        fill={navBackground}
      />
    </Svg>
  );
}

